import{_ as t,c as o,o as a,ai as n}from"./chunks/framework.B9sK0qMe.js";const u=JSON.parse('{"title":"NeoNephos Recap 2025","description":"","frontmatter":{"title":"NeoNephos Recap 2025","date":"2025-12-23","banner":"assets/blog/20251223_year_recap_banner.jpg","authors":["neonephos-team"],"tags":["2025","recap"],"published":true,"sidebar":false,"aside":false,"prev":false,"next":false,"layout":"BlogEntryThemeComponent"},"headers":[],"relativePath":"blog/20251223_recap_2025.md","filePath":"blog/20251223_recap_2025.md"}'),r={name:"blog/20251223_recap_2025.md"};function i(s,e,h,p,l,d){return a(),o("div",null,e[0]||(e[0]=[n('<p>What a year it has been! Although it feels like we have been here for an eternity, it was at the KubeCon 2025 that we announced the launch of the NeoNephos Foundation. By the end of 2025, we have grown to 15 members, with seven of them only joining within the last 6 months. Let us recap this year by looking at key moments that have shaped our foundation:</p><p><strong><a href="https://youtu.be/57koOOg0f5M?list=PLj6h78yzYM2Of6psbKjeZxZIHjycSYoYF" target="_blank" rel="noreferrer">KubeCon 2025 Walk-On</a></strong></p><p>The year started off strong with our foundation launch announcement at the KubeCon 2025. Set on a grand stage flanked by thousands, we introduced the world to our vision of “Making Cloud Native Sovereign”. At our corresponding booth, at that time with Gardener branding, we noticed great interest in our foundation with 200+ people willing to have their badges scanned for follow-up information.</p><p><strong>All Committees formed</strong></p><p>NeoNephos is formally organized into a strategic Governing Board, the Technical Advisory Council and the Technical Steering Committees of each project. Since we launched with 11 projects, this means 13 organizational bodies had to be established. This was a huge undertaking because for many it was the first time they had worked in such a manner. Nevertheless, we persisted. By July we had already formed all committees and established a working mode.</p><p><strong><a href="https://neonephos.org/blog/20250808_ORD_wins_api_award" target="_blank" rel="noreferrer">Open Resource Discovery API Award</a></strong></p><p>It is always worthwhile to revisit the individual accomplishments of our projects, and Open Resource Discovery winning the API Award in the API Standards &amp; Specifications category in August is definitely among them. For us, it is a reminder of the strength of the projects which shape the NeoNephos portfolio.</p><p><strong><a href="https://gardener.cloud/blog/2025/11/11-12-gardener-ai-conformance/" target="_blank" rel="noreferrer">Gardener Reaches CNCF AI Compliance</a></strong></p><p>Each of our projects has enterprise readiness in mind. Therefore, gaining and keeping trust is important. We are proud to mention that Gardener is one of the first Kubernetes offerings which has reached the brand new CNCF Certified Kubernetes AI Conformance. Integrating with de-facto standards and community programs shows our commitment for integration within the wider cloud-native ecosystem. We will continue to push our projects to adhere to state-of-the-art conformance programs, as applicable.</p><p><strong>Platform Mesh Releases</strong></p><p>The year kept going strong with several releases of our Platform Mesh project. This starts by the release of the <a href="https://platform-mesh.io/main/getting-started/example-msp.html" target="_blank" rel="noreferrer">Getting Started guide</a>, which includes a step-by-step introduction into the project and its components, complete with a local Platform Mesh docker environment. Additionally, the project <a href="https://github.com/platform-mesh/ocm/releases/tag/0.1.0" target="_blank" rel="noreferrer">released version 0.1.0</a>, of course packaged via our Open Component Model project.</p><p><strong>NeoNephos joins Zulip</strong></p><p>The foundation and its projects needed an organized team chat, suitable for synchronous and asynchronous communication. Zulip was the perfect candidate as it was hosted and endorsed by the Linux Foundation itself. While the start was slow, it is seeing more and more usage. Help out by <a href="https://linuxfoundation.zulipchat.com/#narrow/channel/525732-neonephos-discussion/topic/channel.20events/with/558483910" target="_blank" rel="noreferrer">joining our Zulip</a> today and shape with us the future of cloud native sovereignty!</p><p><strong>Project Lifecycle Policy Approved</strong></p><p>The year culminated with the approval of a very special document. The project lifecycle policy rules how projects can join the foundation, and the overall roles, responsibilities and benefits a project has with respect to NeoNephos. This is a topic which has led to healthy discussions due to its importance for the foundation as a whole. Nevertheless, we are now in the finish line, having a first version approved by our Governing Board. We are grateful for the continuous feedback we have received from the committee members, the projects, and the Linux Foundation itself during this time. We look forward to unveiling this document to the public soon!</p><p>This closes down our highlights for 2025. Overall, we are well positioned for 2026 and look ahead with great excitement. We wish you a happy holiday and can’t wait for you to come back next year, because we are just getting started!</p>',16)]))}const f=t(r,[["render",i]]);export{u as __pageData,f as default};
